SELECT opt.option_name
FROM `petlog`.order_item oi
         JOIN `petlog`.`order` o ON oi.order_id = o.id
         LEFT JOIN `petlog`.`option` opt ON oi.option_id = opt.id
WHERE o.user_id = #{userId}
  AND oi.product_id = #{productId}

SELECT ROUND(AVG(rating), 1)
FROM petlog.review
WHERE product_id = #{productId}

SELECT (
           SELECT COUNT(*) FROM petlog.order_item oi
                                    JOIN petlog.`order` o ON oi.order_id = o.id
           WHERE o.user_id = #{userId}
             AND oi.product_id = #{productId}
             AND o.created_at >= DATE_SUB(NOW(), INTERVAL 30 DAY)
       ) > (
           SELECT COUNT(*) FROM petlog.review
           WHERE user_id = #{userId}
             AND product_id = #{productId}
       )

mapper.update:
UPDATE petlog.review
SET rating = #{rating}, content = #{content}
WHERE id = #{reviewId} AND user_id = #{userId}
